const { SQSClient, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { DynamoDBClient, UpdateItemCommand } = require('@aws-sdk/client-dynamodb');

const sqs = new SQSClient({ region: 'your-region' });
const dynamodb = new DynamoDBClient({ region: 'your-region' });

async function processMessage(message) {
  // Parse the message body and extract the transaction details
  const transactionDetails = JSON.parse(message.Body);

  // Update the database with the transaction details
  await dynamodb.updateItem({
    TableName: 'your-table-name',
    Key: {
      id: transactionDetails.id,
    },
    UpdateExpression: 'set status = :status',
    ExpressionAttributeValues: {
      ':status': transactionDetails.status,
    },
  });

  // Delete the message from the queue
  await sqs.deleteMessage({
    QueueUrl: 'your-queue-url',
    ReceiptHandle: message.ReceiptHandle,
  });
}

async function consumeMessages() {
  const params = {
    AttributeNames: ['SentTimestamp'],
    MaxNumberOfMessages: 10,
    MessageAttributeNames: ['All'],
    QueueUrl: 'your-queue-url',
    VisibilityTimeout: 30,
  };

  while (true) {
    const response = await sqs.receiveMessage(params).promise();
    if (!response.Messages || !response.Messages.length) {
      break;
    }

    for (const message of response.Messages) {
      try {
        await processMessage(message);
      } catch (error) {
        console.log(`Error processing message: ${error}`);
      }
    }
  }
}

consumeMessages();